// ASCII 流程圖範例：
// [開始]
//   |
// <年齡 >= 18?>
//  /       \
// Yes       No
// |          |
// <有身分證?>  [告知未成年]
//  /     \       |
// Yes     No   [結束]
// |        |
// [通過]  [請補件]
// |        |
// [結束]  [結束]

// 對應程式碼：
let age = 20;
let hasID = true;

if (age >= 18) {
  if (hasID) {
    console.log("通過");
  } else {
    console.log("請補件");
  }
} else {
  console.log("未成年，不能進");
}

